74	// NewPostAttemptTriageHook constructs the bead-lifecycle post-attempt triage
75	// hook. The hook is runner-backed, uses the resolved config / runner dispatch
76	// seam, and never shells out through os/exec.
77	func NewPostAttemptTriageHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner, sessionLogReader SessionLogExcerptReader) func(ctx context.Context, beadID string, report ExecuteBeadReport) (TriageResult, error) {
78		reader := sessionLogReader
79		if reader == nil {
80			reader = fileSessionLogExcerptReader{}
81		}
82		return func(ctx context.Context, beadID string, report ExecuteBeadReport) (TriageResult, error) {
83			if ctx != nil {
84				if err := ctx.Err(); err != nil {
85					return TriageResult{}, err
86				}
87			}
88			if store == nil {
89				return TriageResult{}, fmt.Errorf("triage hook: bead reader required")
90			}
91			if err := ensureBeadLifecycleSkill(projectRoot); err != nil {
92				return TriageResult{}, fmt.Errorf("triage hook: %w", err)
93			}
94	
95			b, err := store.Get(ctx, beadID)
96			if err != nil {
97				return TriageResult{}, fmt.Errorf("triage hook: load bead %s: %w", beadID, err)
98			}
99	
100			var eventLister interface {

100			var eventLister interface {
101				Events(id string) ([]bead.BeadEvent, error)
102			}
103			if l, ok := any(store).(interface {
104				Events(id string) ([]bead.BeadEvent, error)
105			}); ok {
106				eventLister = l
107			}
108	
109			prompt, err := buildPostAttemptTriagePrompt(ctx, projectRoot, b, report, reader, eventLister)
110			if err != nil {
111				return TriageResult{}, err
112			}
113	
114			result, err := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, AgentRunRuntime{
115				Prompt:           prompt,
116				WorkDir:          projectRoot,
117				PromptSource:     postAttemptTriagePromptSource,
118				ClearRoutingPins: true,
119				ClearProfile:     true,
120				ClearMinPower:    true,
121				ClearMaxPower:    true,
122			})
123			if err != nil {
124				return TriageResult{}, fmt.Errorf("triage hook: dispatch: %w", err)
125			}
126	
127			text, err := triageResultOutput(result)
128			if err != nil {
129				return TriageResult{}, err
130			}
131			if text == "" {
132				return malformedTriageResult("output", "empty output", ""), nil
133			}
134	
135			payload, ok := extractJSONCandidate(text)
136			if !ok {
137				return malformedTriageResult("output", "no JSON object found", text), nil
138			}
139	
140			out := decodeTriageResult(payload)
141			if len(out.DecodeWarnings) > 0 {
142				out.Malformed = true
143			}
144			return out, nil
145		}
146	}
