254			"suggested_amendments":     amendments,
255			"suggested_followup_beads": followups,
256			"status":                   report.Status,
257			"detail":                   report.Detail,
258			"base_rev":                 report.BaseRev,
259			"result_rev":               report.ResultRev,
260			"session_id":               report.SessionID,
261		}
262		if len(triage.DecodeWarnings) > 0 {
263			body["decode_warnings"] = triage.DecodeWarnings
264		}
265		if triage.Malformed {
266			body["malformed"] = true
267		}
268		encoded, err := json.Marshal(body)
269		if err != nil {
270			return
271		}
272		kind := "bead-quality.triage"
273		summary := triage.Classification
274		if !isRecognizedTriageClassification(triage.Classification) {
275			kind = "bead-quality.triage-warning"
276			summary = "malformed triage output"
277			if triage.Classification != "" {
278				summary = "unusable triage classification: " + triage.Classification
279			} else if len(triage.DecodeWarnings) > 0 && triage.DecodeWarnings[0].Warning != "" {
280				summary = triage.DecodeWarnings[0].Warning
281			}
282		} else if triage.RecommendedAction != "" {
283			summary = triage.Classification + ": " + triage.RecommendedAction
284			if len(triage.DecodeWarnings) > 0 {
285				summary += fmt.Sprintf(" (warnings=%d)", len(triage.DecodeWarnings))
286			}
