func TestReadiness_DiscountesStalEternalBlockerWhenNewerNoteClearsIt(t *testing.T) {
	root := newPreClaimIntakeHookTestRoot(t)
	inner, beadRef := newPreClaimIntakeHookTestStore(t, root)
	store := &parkCountingStore{claimCountingStore: &claimCountingStore{Store: inner}}

	staleBlockerTime := time.Date(2026, 5, 15, 10, 0, 0, 0, time.UTC)
	clearedTime := time.Date(2026, 5, 18, 14, 30, 0, 0, time.UTC)

	require.NoError(t, inner.Update(beadRef.ID, func(b *bead.Bead) {
		b.Notes = "Unblocked 2026-05-18: the prior Redpanda/AIO blocker was stale after commit 90cd8348 bounded Redpanda test storage with an owned tmpfs mount... The container became ready and was cleaned up."
	}))

	require.NoError(t, inner.AppendEvent(beadRef.ID, bead.BeadEvent{
		Kind:      "no_changes_blocked",
		Summary:   "Redpanda fails to start due to AIO slot exhaustion on WSL2",
		Body:      `{"reason":"external_infrastructure","detail":"Redpanda environment can support 32-partition stress test, but infrastructure provisioning in WSL2 environment fails.","blocker":"redpanda AIO slot exhaustion"}`,
		Actor:     "ddx work",
		CreatedAt: staleBlockerTime,
		Source:    "ddx work",
	}))

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-stale-blocker",
				ResultRev: "stale-blocker",
			}, nil
		}),
	}

	svc := &preClaimIntakeHookServiceStub{
		finalText: `{"classification":"ready","rationale":"bead is executable","readiness_checks":[]}`,
	}
	intakeHook := NewPreClaimIntakeHook(root, store, intakeHookTestConfig(), svc, nil)

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:               true,
		PreClaimIntakeHook: intakeHook,
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	assert.Equal(t, int32(1), atomic.LoadInt32(&store.claimCalls), "stale blocker + newer clearing note must still claim")
	assert.Equal(t, int32(0), atomic.LoadInt32(&store.parkCalls), "stale blocker + newer clearing note must not park")
	assert.Equal(t, 1, result.Attempts)
	assert.Equal(t, 1, result.Successes)

	got, err := inner.Get(beadRef.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusClosed, got.Status)
	assert.Contains(t, got.Notes, "Unblocked 2026-05-18")
}

